     5→//! VOK Main - Voce Viva Rust binary entry point
     6→//!
     7→//! Provides core VOK commands and delegates kit commands via external subcommand pattern.
     8→//! JJK commands (jjx_*) are handled entirely by the jjk crate when the feature is enabled.
     9→
    10→use clap::Parser;
    11→use std::ffi::OsString;
    12→use std::path::PathBuf;
    13→use std::process::ExitCode;
    14→
    15→#[derive(Parser)]
    16→#[command(name = "vvr")]
    17→#[command(version)]
    18→#[command(about = "Voce Viva Rust - Platform utilities for Claude Code kits")]
    19→#[command(allow_external_subcommands = true)]
    20→struct Cli {
    21→    #[command(subcommand)]
    22→    command: Option<Commands>,
    23→}
    24→
    25→#[derive(clap::Subcommand)]
    26→enum Commands {
    27→    /// Pre-commit size validation
    28→    Guard(GuardArgs),
    29→
    30→    /// Atomic commit with lock, stage, guard, and optional claude message
    31→    #[command(name = "vvx_commit")]
    32→    VvxCommit(CommitArgs),
    33→
    34→    /// Push with lock (prevents concurrent push/commit)
    35→    #[command(name = "vvx_push")]
    36→    VvxPush(PushArgs),
    37→
    38→    /// Force-break a stuck lock (use after crash)
    39→    #[command(name = "vvx_unlock")]
    40→    VvxUnlock,
    41→
    42→    /// Collect kit assets to staging directory
    43→    #[command(name = "release_collect")]
    44→    ReleaseCollect(ReleaseCollectArgs),
    45→
    46→    /// Brand staging directory with hallmark
    47→    #[command(name = "release_brand")]
    48→    ReleaseBrand(ReleaseBrandArgs),
    49→
    50→    /// Install kit assets from parcel to target repo
    51→    #[command(name = "vvx_emplace")]
    52→    VvxEmplace(EmplaceArgs),
    53→
    54→    /// Remove kit assets from target repo
    55→    #[command(name = "vvx_vacate")]
    56→    VvxVacate(VacateArgs),
    57→
    58→    /// External subcommands (delegated to kit CLIs)
    59→    #[command(external_subcommand)]
    60→    External(Vec<OsString>),
    61→}
    62→
    63→/// Arguments for guard command (wraps vvc)
    64→#[derive(clap::Args, Debug)]
    65→struct GuardArgs {
    66→    /// Size limit in bytes (default: 500000)
    67→    #[arg(long, default_value = "500000")]
    68→    limit: u64,
    69→
    70→    /// Warning threshold in bytes (default: 250000)
    71→    #[arg(long, default_value = "250000")]
    72→    warn: u64,
    73→}
    74→
    75→/// Arguments for vvx_commit command (wraps vvc)
    76→#[derive(clap::Args, Debug)]
    77→struct CommitArgs {
    78→    /// Prefix string to prepend to commit message
    79→    #[arg(long)]
    80→    prefix: Option<String>,
    81→
    82→    /// Commit message; if absent, invoke claude to generate from diff
    83→    #[arg(short, long)]
    84→    message: Option<String>,
    85→
    86→    /// Allow empty commits
    87→    #[arg(long)]
    88→    allow_empty: bool,
    89→
    90→    /// Skip 'git add -A' (respect pre-staged files)
    91→    #[arg(long)]
    92→    no_stage: bool,
    93→}
    94→
    95→/// Arguments for vvx_push command
    96→#[derive(clap::Args, Debug)]
    97→struct PushArgs {
    98→    /// Remote name (default: origin)
    99→    #[arg(long, default_value = "origin")]
   100→    remote: String,
   101→
   102→    /// Branch name (default: current branch)
   103→    #[arg(long)]
   104→    branch: Option<String>,
   105→
   106→    /// Force push (use with caution)
   107→    #[arg(long)]
   108→    force: bool,
   109→}
   110→
   111→/// Arguments for release_collect command
   112→#[derive(clap::Args, Debug)]
   113→struct ReleaseCollectArgs {
   114→    /// Staging directory to populate
   115→    #[arg(long)]
   116→    staging: PathBuf,
   117→
   118→    /// Source Tools/ directory
   119→    #[arg(long)]
   120→    tools_dir: PathBuf,
   121→
   122→    /// Path to vvi_install.sh
   123→    #[arg(long)]
   124→    install_script: PathBuf,
   125→
   126→    /// Comma-separated list of kit IDs (from BURC_MANAGED_KITS)
   127→    #[arg(long)]
   128→    managed_kits: String,
   129→}
   130→
   131→/// Arguments for release_brand command
   132→#[derive(clap::Args, Debug)]
   133→struct ReleaseBrandArgs {
   134→    /// Staging directory with collected assets
   135→    #[arg(long)]
   136→    staging: PathBuf,
   137→
   138→    /// Path to vovr_registry.json
   139→    #[arg(long)]
   140→    registry: PathBuf,
   141→
   142→    /// Current git commit SHA
   143→    #[arg(long)]
   144→    commit: String,
   145→
   146→    /// Comma-separated list of kit IDs (from BURC_MANAGED_KITS)
   147→    #[arg(long)]
   148→    managed_kits: String,
   149→}
   150→
   151→/// Arguments for vvx_emplace command
   152→#[derive(clap::Args, Debug)]
   153→struct EmplaceArgs {
   154→    /// Extracted parcel directory (contains vvbf_brand.json, kits/)
   155→    #[arg(long)]
   156→    parcel: PathBuf,
   157→
   158→    /// Path to target repo's burc.env file
   159→    #[arg(long)]
   160→    burc: PathBuf,
   161→}
   162→
   163→/// Arguments for vvx_vacate command
   164→#[derive(clap::Args, Debug)]
   165→struct VacateArgs {
   166→    /// Path to target repo's burc.env file
   167→    #[arg(long)]
   168→    burc: PathBuf,
   169→}
   170→
   171→fn main() -> ExitCode {
   172→    let cli = Cli::parse();
   173→
   174→    let exit_code = match cli.command {
   175→        Some(Commands::Guard(args)) => run_guard(args),
   176→        Some(Commands::VvxCommit(args)) => run_commit(args),
   177→        Some(Commands::VvxPush(args)) => run_push(args),
   178→        Some(Commands::VvxUnlock) => run_unlock(),
   179→        Some(Commands::ReleaseCollect(args)) => run_release_collect(args),
   180→        Some(Commands::ReleaseBrand(args)) => run_release_brand(args),
   181→        Some(Commands::VvxEmplace(args)) => run_emplace(args),
   182→        Some(Commands::VvxVacate(args)) => run_vacate(args),
   183→        Some(Commands::External(args)) => dispatch_external(args),
   184→        None => {
   185→            use clap::CommandFactory;
   186→            Cli::command().print_help().ok();
   187→            0
   188→        }
   189→    };
   190→
   191→    ExitCode::from(exit_code as u8)
   192→}
   193→
   194→/// Run guard command using vvc
   195→fn run_guard(args: GuardArgs) -> i32 {
   196→    let vvc_args = vvc::vvcg_GuardArgs {
   197→        limit: args.limit,
   198→        warn: args.warn,
   199→    };
   200→    vvc::guard(&vvc_args, None)
   201→}
   202→
   203→/// Run commit command using vvc
   204→fn run_commit(args: CommitArgs) -> i32 {
   205→    let vvc_args = vvc::vvcc_CommitArgs {
   206→        prefix: args.prefix,
   207→        message: args.message,
   208→        allow_empty: args.allow_empty,
   209→        no_stage: args.no_stage,
   210→        size_limit: vvc::VVCG_SIZE_LIMIT,
   211→        warn_limit: vvc::VVCG_WARN_LIMIT,
   212→    };
   213→    vvc::commit(&vvc_args)
   214→}
   215→
   216→/// Dispatch external subcommands to appropriate kit CLIs
   217→fn dispatch_external(args: Vec<OsString>) -> i32 {
   218→    if args.is_empty() {
   219→        eprintln!("vvx: error: no subcommand provided");
   220→        return 1;
   221→    }
   222→
   223→    let cmd_name = args[0].to_string_lossy();
   224→
   225→    // Delegate to JJK if available and command matches
   226→    #[cfg(feature = "jjk")]
   227→    if jjk::jjrx_is_jjk_command(&cmd_name) {
   228→        return jjk::jjrx_dispatch(&args);
   229→    }
   230→
   231→    // Unknown external subcommand
   232→    eprintln!("vvx: error: unknown command '{}'", cmd_name);
   233→    eprintln!("Run 'vvx --help' for available commands");
   234→    1
   235→}
   236→
   237→/// Lock reference path for push operations (same as commit to prevent concurrent ops)
   238→const LOCK_REF: &str = "refs/vvg/locks/vvx";
   239→
   240→/// Force-break a stuck lock
   241→fn run_unlock() -> i32 {
   242→    use std::process::Command;
   243→
   244→    // Check if lock exists
   245→    let check = Command::new("git")
   246→        .args(["show-ref", "--verify", "--quiet", LOCK_REF])
   247→        .status();
   248→
   249→    match check {
   250→        Ok(status) if status.success() => {
   251→            // Lock exists, delete it
   252→            let delete = Command::new("git")
   253→                .args(["update-ref", "-d", LOCK_REF])
   254→                .output();
   255→
   256→            match delete {
   257→                Ok(output) if output.status.success() => {
   258→                    eprintln!("unlock: lock broken successfully");
   259→                    0
   260→                }
   261→                Ok(output) => {
   262→                    eprintln!("unlock: error: failed to delete lock: {}",
   263→                        String::from_utf8_lossy(&output.stderr));
   264→                    1
   265→                }
   266→                Err(e) => {
   267→                    eprintln!("unlock: error: {}", e);
   268→                    1
   269→                }
   270→            }
   271→        }
   272→        Ok(_) => {
   273→            // Lock doesn't exist
   274→            eprintln!("unlock: no lock held");
   275→            0
   276→        }
   277→        Err(e) => {
   278→            eprintln!("unlock: error checking lock: {}", e);
   279→            1
   280→        }
   281→    }
   282→}
   283→
   284→fn run_push(args: PushArgs) -> i32 {
   285→    use std::process::Command;
   286→
   287→    eprintln!("push: acquiring lock...");
   288→    let head_output = Command::new("git")
   289→        .args(["rev-parse", "HEAD"])
   290→        .output();
   291→
   292→    let lock_value = match head_output {
   293→        Ok(output) if output.status.success() => {
   294→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   295→        }
   296→        _ => "0000000000000000000000000000000000000000".to_string(),
   297→    };
   298→
   299→    let lock_result = Command::new("git")
   300→        .args(["update-ref", LOCK_REF, &lock_value, ""])
   301→        .output();
   302→
   303→    match lock_result {
   304→        Ok(output) if output.status.success() => {
   305→            eprintln!("push: lock acquired");
   306→        }
   307→        _ => {
   308→            eprintln!("push: error: Another operation in progress - lock held");
   309→            return 1;
   310→        }
   311→    }
   312→
   313→    let result = run_push_workflow(&args);
   314→
   315→    let _ = Command::new("git")
   316→        .args(["update-ref", "-d", LOCK_REF])
   317→        .output();
   318→    eprintln!("push: lock released");
   319→
   320→    match result {
   321→        Ok(()) => {
   322→            eprintln!("push: success");
   323→            0
   324→        }
   325→        Err(e) => {
   326→            eprintln!("push: error: {}", e);
   327→            1
   328→        }
   329→    }
   330→}
   331→
   332→fn run_push_workflow(args: &PushArgs) -> Result<(), String> {
   333→    use std::process::Command;
   334→
   335→    let branch = match &args.branch {
   336→        Some(b) => b.clone(),
   337→        None => {
   338→            let output = Command::new("git")
   339→                .args(["rev-parse", "--abbrev-ref", "HEAD"])
   340→                .output()
   341→                .map_err(|e| format!("Failed to get current branch: {}", e))?;
   342→
   343→            if !output.status.success() {
   344→                return Err("Failed to determine current branch".to_string());
   345→            }
   346→
   347→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   348→        }
   349→    };
   350→
   351→    eprintln!("push: pushing {} to {}", branch, args.remote);
   352→
   353→    let mut push_args = vec!["push", &args.remote, &branch];
   354→    if args.force {
   355→        push_args.push("--force");
   356→    }
   357→
   358→    let output = Command::new("git")
   359→        .args(&push_args)
   360→        .output()
   361→        .map_err(|e| format!("Failed to run git push: {}", e))?;
   362→
   363→    if !output.status.success() {
   364→        let stderr = String::from_utf8_lossy(&output.stderr);
   365→        return Err(format!("git push failed: {}", stderr));
   366→    }
   367→
   368→    Ok(())
   369→}
   370→
   371→/// Run release_collect command
   372→fn run_release_collect(args: ReleaseCollectArgs) -> i32 {
   373→    eprintln!("release_collect: collecting assets...");
   374→    eprintln!("  staging: {}", args.staging.display());
   375→    eprintln!("  tools_dir: {}", args.tools_dir.display());
   376→    eprintln!("  install_script: {}", args.install_script.display());
   377→
   378→    // Parse comma-separated kit list
   379→    let managed_kits: Vec<String> = args.managed_kits
   380→        .split(',')
   381→        .map(|s| s.trim().to_string())
   382→        .filter(|s| !s.is_empty())
   383→        .collect();
   384→
   385→    match vof::vofr_collect(&args.tools_dir, &args.staging, &args.install_script, &managed_kits) {
   386→        Ok(result) => {
   387→            // Output JSON for bash to parse
   388→            let mut output = serde_json::Map::new();
   389→            output.insert("total_files".to_string(), serde_json::Value::Number(result.total_files.into()));
   390→            output.insert("commands_routed".to_string(), serde_json::Value::Number(result.commands_routed.into()));
   391→
   392→            let kit_counts: serde_json::Map<String, serde_json::Value> = result.kit_counts
   393→                .into_iter()
   394→                .map(|(k, v)| (k, serde_json::Value::Number(v.into())))
   395→                .collect();
   396→            output.insert("kit_counts".to_string(), serde_json::Value::Object(kit_counts));
   397→
   398→            println!("{}", serde_json::to_string_pretty(&serde_json::Value::Object(output)).unwrap());
   399→            eprintln!("release_collect: success - {} files collected", result.total_files);
   400→            0
   401→        }
   402→        Err(e) => {
   403→            eprintln!("release_collect: error: {}", e);
   404→            1
   405→        }
   406→    }
   407→}
   408→
   409→/// Run release_brand command
   410→fn run_release_brand(args: ReleaseBrandArgs) -> i32 {
   411→    eprintln!("release_brand: branding staging...");
   412→    eprintln!("  staging: {}", args.staging.display());
   413→    eprintln!("  registry: {}", args.registry.display());
   414→    eprintln!("  commit: {}", args.commit);
   415→
   416→    // Parse comma-separated kit list
   417→    let managed_kits: Vec<String> = args.managed_kits
   418→        .split(',')
   419→        .map(|s| s.trim().to_string())
   420→        .filter(|s| !s.is_empty())
   421→        .collect();
   422→
   423→    match vof::vofr_brand(&args.staging, &args.registry, &args.commit, &managed_kits) {
   424→        Ok(result) => {
   425→            // Output hallmark for bash to use in tarball name
   426→            println!("{}", result.hallmark);
   427→            if result.is_new {
   428→                eprintln!("release_brand: allocated new hallmark {}", result.hallmark);
   429→            } else {
   430→                eprintln!("release_brand: reusing existing hallmark {}", result.hallmark);
   431→            }
   432→            eprintln!("release_brand: super-SHA: {}", result.super_sha);
   433→            0
   434→        }
   435→        Err(e) => {
   436→            eprintln!("release_brand: error: {}", e);
   437→            1
   438→        }
   439→    }
   440→}
   441→
   442→/// Run vvx_emplace command
   443→fn run_emplace(args: EmplaceArgs) -> i32 {
   444→    eprintln!("emplace: installing kit assets...");
   445→    eprintln!("  parcel: {}", args.parcel.display());
   446→    eprintln!("  burc: {}", args.burc.display());
   447→
   448→    let emplace_args = vof::vofe_EmplaceArgs {
   449→        parcel_dir: args.parcel,
   450→        burc_path: args.burc,
   451→    };
   452→
   453→    match vof::vofe_emplace(&emplace_args) {
   454→        Ok(result) => {
   455→            // Output JSON summary
   456→            let mut output = serde_json::Map::new();
   457→            output.insert("hallmark".to_string(), serde_json::Value::Number(result.hallmark.into()));
   458→
   459→            let kits: Vec<serde_json::Value> = result.kits_installed
   460→                .iter()
   461→                .map(|k| serde_json::Value::String(k.clone()))
   462→                .collect();
   463→            output.insert("kits_installed".to_string(), serde_json::Value::Array(kits));
   464→
   465→            output.insert("files_copied".to_string(), serde_json::Value::Number(result.files_copied.into()));
   466→            output.insert("commands_routed".to_string(), serde_json::Value::Number(result.commands_routed.into()));
   467→            output.insert("hooks_routed".to_string(), serde_json::Value::Number(result.hooks_routed.into()));
   468→
   469→            let sections: Vec<serde_json::Value> = result.claude_sections_updated
   470→                .iter()
   471→                .map(|s| serde_json::Value::String(s.clone()))
   472→                .collect();
   473→            output.insert("claude_sections_updated".to_string(), serde_json::Value::Array(sections));
   474→
   475→            println!("{}", serde_json::to_string_pretty(&serde_json::Value::Object(output)).unwrap());
   476→
   477→            eprintln!("emplace: success - {} files, {} commands, {} hooks",
   478→                result.files_copied, result.commands_routed, result.hooks_routed);
   479→            0
   480→        }
   481→        Err(e) => {
   482→            eprintln!("emplace: error: {}", e);
   483→            1
   484→        }
   485→    }
   486→}
   487→
   488→/// Run vvx_vacate command
   489→fn run_vacate(args: VacateArgs) -> i32 {
   490→    eprintln!("vacate: removing kit assets...");
   491→    eprintln!("  burc: {}", args.burc.display());
   492→
   493→    let vacate_args = vof::vofe_VacateArgs {
   494→        burc_path: args.burc,
   495→    };
   496→
   497→    match vof::vofe_vacate(&vacate_args) {
   498→        Ok(result) => {
   499→            // Output JSON summary
   500→            let mut output = serde_json::Map::new();
   501→
   502→            let kits: Vec<serde_json::Value> = result.kits_removed
   503→                .iter()
   504→                .map(|k| serde_json::Value::String(k.clone()))
   505→                .collect();
   506→            output.insert("kits_removed".to_string(), serde_json::Value::Array(kits));
   507→
   508→            output.insert("files_deleted".to_string(), serde_json::Value::Number(result.files_deleted.into()));
   509→            output.insert("commands_removed".to_string(), serde_json::Value::Number(result.commands_removed.into()));
   510→            output.insert("hooks_removed".to_string(), serde_json::Value::Number(result.hooks_removed.into()));
   511→
   512→            let sections: Vec<serde_json::Value> = result.claude_sections_collapsed
   513→                .iter()
   514→                .map(|s| serde_json::Value::String(s.clone()))
   515→                .collect();
   516→            output.insert("claude_sections_collapsed".to_string(), serde_json::Value::Array(sections));
   517→
   518→            println!("{}", serde_json::to_string_pretty(&serde_json::Value::Object(output)).unwrap());
   519→
   520→            eprintln!("vacate: success - {} files, {} commands, {} hooks removed",
   521→                result.files_deleted, result.commands_removed, result.hooks_removed);
   522→            0
   523→        }
   524→        Err(e) => {
   525→            eprintln!("vacate: error: {}", e);
   526→            1
   527→        }
   528→    }
   529→}
